FIFO="/root/alvaro/exabgp-3.4.11/var/run/exabgp/exabgp.cmd"
trap "rm -f $FIFO; exit" SIGINT

mkfifo $FIFO
chmod 660 $FIFO

while true
do
    if read line; then
        echo $line
    else
        sleep 1
    fi
done < $FIFO

========================================================================

